+        message: "route on session",
+        sessionKey: "agent:main:main",
+        deliver: true,
+      }),
+    });
+
+    expect(agentCommandMock).toHaveBeenCalledTimes(1);
+    const [opts] = agentCommandMock.mock.calls[0] ?? [];
